from PySide6 import QtCore, QtWidgets
from PySide6.QtCore import Qt
from videotrans.configure.config import tr, params,settings
from videotrans.configure import contants
from videotrans.util.help_misc import open_url


class Ui_xiaomiform(object):
    def setupUi(self, xiaomiform):
        self.has_done = False
        xiaomiform.setObjectName("xiaomiform")
        xiaomiform.setWindowModality(QtCore.Qt.NonModal)
        xiaomiform.resize(600, 550)
        sizePolicy = QtWidgets.QSizePolicy(QtWidgets.QSizePolicy.Fixed, QtWidgets.QSizePolicy.Fixed)
        sizePolicy.setHorizontalStretch(0)
        sizePolicy.setVerticalStretch(0)
        sizePolicy.setHeightForWidth(xiaomiform.sizePolicy().hasHeightForWidth())
        xiaomiform.setSizePolicy(sizePolicy)
        xiaomiform.setMaximumSize(QtCore.QSize(600, 500))

        v1 = QtWidgets.QVBoxLayout(xiaomiform)

        h1 = QtWidgets.QHBoxLayout()
        self.label_2 = QtWidgets.QLabel()
        self.label_2.setMinimumSize(QtCore.QSize(0, 35))
        self.label_2.setSizeIncrement(QtCore.QSize(0, 35))
        self.label_2.setObjectName("label_2")
        self.xiaomi_key = QtWidgets.QLineEdit()
        self.xiaomi_key.setMinimumSize(QtCore.QSize(0, 35))
        self.xiaomi_key.setObjectName("xiaomi_key")
        h1.addWidget(self.label_2)
        h1.addWidget(self.xiaomi_key)
        v1.addLayout(h1)

        h2 = QtWidgets.QHBoxLayout()
        self.label_3 = QtWidgets.QLabel()
        self.label_3.setObjectName("label_3")
        self.model = QtWidgets.QComboBox()
        self.model.setMinimumSize(QtCore.QSize(0, 35))
        self.model.setObjectName("model")
        h2.addWidget(self.label_3)
        h2.addWidget(self.model)
        v1.addLayout(h2)
        
        
        h_token=QtWidgets.QHBoxLayout()
        label_token = QtWidgets.QLabel()
        label_token.setObjectName("label_token")
        label_token.setText('Max Token')
        self.xiaomi_maxtoken = QtWidgets.QLineEdit()
        self.xiaomi_maxtoken.setObjectName("xiaomi_maxtoken")
        
        self.xiaomi_thinking = QtWidgets.QCheckBox()
        self.xiaomi_thinking.setText('Thinking')
        
        h_token.addWidget(label_token)
        h_token.addWidget(self.xiaomi_maxtoken)
        h_token.addWidget(self.xiaomi_thinking)
        
        
        v1.addLayout(h_token)
        

        self.label_allmodels = QtWidgets.QLabel()
        self.label_allmodels.setObjectName("label_allmodels")
        self.label_allmodels.setText(
            tr("Fill in all available models, separated by commas. After filling in, you can select them above"))
        self.label_allmodels.setStyleSheet("color:#999")

        self.edit_allmodels = QtWidgets.QPlainTextEdit()
        self.edit_allmodels.setObjectName("edit_allmodels")
        v1.addWidget(self.label_allmodels)
        v1.addWidget(self.edit_allmodels)

        self.label_4 = QtWidgets.QLabel()
        self.label_4.setObjectName("label_4")
        self.xiaomi_template = QtWidgets.QPlainTextEdit()
        self.xiaomi_template.setObjectName("xiaomi_template")
        self.xiaomi_template.setReadOnly(True)
        v1.addWidget(self.label_4)
        v1.addWidget(self.xiaomi_template)



        h2ttsmodel = QtWidgets.QHBoxLayout()
        self.label_ttsmodel = QtWidgets.QLabel()
        self.label_ttsmodel.setObjectName("label_ttsmodel")
        self.label_ttsmodel.setText('TTS model')

        self.ttsmodel = QtWidgets.QComboBox()
        self.ttsmodel.setMinimumSize(QtCore.QSize(0, 35))
        self.ttsmodel.setObjectName("ttsmodel")
        self.ttsmodel.addItems(contants.XIAOMI_TTS_MODELS.split(','))
        h2ttsmodel.addWidget(self.label_ttsmodel)
        h2ttsmodel.addWidget(self.ttsmodel)
        v1.addLayout(h2ttsmodel)

        h3 = QtWidgets.QHBoxLayout()
        self.set_xiaomi = QtWidgets.QPushButton()
        self.set_xiaomi.setMinimumSize(QtCore.QSize(0, 35))
        self.set_xiaomi.setObjectName("set_xiaomi")

        self.test = QtWidgets.QPushButton()
        self.test.setObjectName("test")

        help_btn = QtWidgets.QPushButton()
        help_btn.setMinimumSize(QtCore.QSize(0, 35))
        help_btn.setStyleSheet("background-color: rgba(255, 255, 255,0)")
        help_btn.setObjectName("help_btn")
        help_btn.setCursor(Qt.PointingHandCursor)
        help_btn.setText(tr("Fill out the tutorial"))
        help_btn.clicked.connect(lambda: open_url(url='https://pyvideotrans.com/xiaomi'))

        h3.addWidget(self.set_xiaomi)
        h3.addWidget(self.test)
        h3.addWidget(help_btn)
        v1.addLayout(h3)
        self.xiaomi_template.setPlainText(tr("Prompt: Please open the {} file directly to modify it", 'xiaomi', 'xiaomi'))
        xiaomiform.setWindowTitle("xiaomi AI")
        self.retranslateUi()
        QtCore.QMetaObject.connectSlotsByName(xiaomiform)


    def update_ui(self):
        allmodels_str = settings.get('xiaomi_model','')
        allmodels = str(settings.get('xiaomi_model','')).split(',')
        self.model.clear()
        self.model.addItems(allmodels)
        self.edit_allmodels.setPlainText(allmodels_str)
        self.xiaomi_key.setText(str(params.get("xiaomi_key",'')))
        self.model.setCurrentText(params.get("xiaomi_model",''))
        self.xiaomi_thinking.setChecked(bool(params.get("xiaomi_thinking",False)))
        
        self.xiaomi_maxtoken.setText(str(params.get("xiaomi_maxtoken",'18192')))

        self.ttsmodel.setCurrentText(params.get("xiaomi_ttsmodel",''))

    def retranslateUi(self):
        
        self.xiaomi_template.setPlaceholderText("prompt")
        self.label_4.setText(
            tr("{lang} represents the target language name, do not delete it."))
        self.label_4.setStyleSheet("color: #999;")
        self.set_xiaomi.setText(tr("Save"))
        self.test.setText(tr("Test"))
        self.xiaomi_key.setPlaceholderText("secret key")
        self.label_2.setText("xiaomi  Key ")
        self.label_3.setText(tr("Select model"))
